import{c as a,Q as r,j as t,m as o}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Prepare a set","description":"","frontmatter":{},"headers":[],"relativePath":"ru/workflows/prepare-a-set.md","filePath":"ru/workflows/prepare-a-set.md","lastUpdated":null}'),d={name:"ru/workflows/prepare-a-set.md"};function s(i,e,n,l,c,p){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="prepare-a-set" tabindex="-1">Prepare a set <a class="header-anchor" href="#prepare-a-set" aria-label="Permalink to &quot;Prepare a set&quot;">​</a></h1><p>Аудитория: DJs, работающие в browser UI<br> Цель: превратить несколько tracks в reviewed export<br> Тип: tutorial</p><p>Workflow начинается с trusted tracks, затем создает candidates, строит preview и экспортирует только после ручной проверки.</p><h2 id="before-you-start" tabindex="-1">Before you start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before you start&quot;">​</a></h2><p>Нужна scanned library и analysis для выбранного search mode:</p><ul><li>SONARA features для explainable feature search;</li><li>MERT embeddings для audio seed similarity;</li><li>CLAP embeddings для text prompts;</li><li>SONARA, MERT, MAEST и CLAP для Smart Set Builder.</li></ul><h2 id="_1-pick-first-anchors" tabindex="-1">1. Pick first anchors <a class="header-anchor" href="#_1-pick-first-anchors" aria-label="Permalink to &quot;1. Pick first anchors&quot;">​</a></h2><p>В library table найдите один-пять tracks, представляющих нужный sound. Если планируете SET, не выбирайте несколько tracks одного known artist: SET сохраняет strict artist guard.</p><h2 id="_2-search-around-anchors" tabindex="-1">2. Search around anchors <a class="header-anchor" href="#_2-search-around-anchors" aria-label="Permalink to &quot;2. Search around anchors&quot;">​</a></h2><p>Используйте tab под задачу:</p><table tabindex="0"><thead><tr><th>Need</th><th>Tab</th></tr></thead><tbody><tr><td>похожий audio feel от selected tracks</td><td><code>MERT</code></td></tr><tr><td>explainable musical features</td><td><code>SONARA</code></td></tr><tr><td>text prompt вроде &quot;dark rolling techno&quot;</td><td><code>CLAP</code></td></tr><tr><td>ordered set preview</td><td><code>SET</code></td></tr><tr><td>promoted personal concept</td><td><code>CLASS</code></td></tr></tbody></table><p>Добавляйте только candidates, которые хотите слушать. Search results не являются finished set.</p><h2 id="_3-generate-set-preview" tabindex="-1">3. Generate SET preview <a class="header-anchor" href="#_3-generate-set-preview" aria-label="Permalink to &quot;3. Generate SET preview&quot;">​</a></h2><p>Откройте <code>SET</code>, выберите <code>Manual</code> или <code>Auto</code>, задайте track limit, energy curve, diversity и BPM mode, затем generate preview.</p><p>Preview read-only. Оно становится частью current set только через явное add action.</p><h2 id="_4-listen-and-remove-weak-links" tabindex="-1">4. Listen and remove weak links <a class="header-anchor" href="#_4-listen-and-remove-weak-links" aria-label="Permalink to &quot;4. Listen and remove weak links&quot;">​</a></h2><p>Используйте playback, metadata, BPM/key и собственный DJ judgement. Similarity scores - ranking hints, а не знание о room, crowd или transition style.</p><h2 id="_5-export" tabindex="-1">5. Export <a class="header-anchor" href="#_5-export" aria-label="Permalink to &quot;5. Export&quot;">​</a></h2><p>Когда current set полезен, export его как playlist/report из UI. Export пишет playlist/report files и не переписывает source audio.</p>',19)])])}const k=a(d,[["render",s]]);export{u as __pageData,k as default};
